extension URL {
    var queryParameters: [String: String] {
        guard let queryString = URLComponents(url: self, resolvingAgainstBaseURL: true)?.query else { return [:] }
        
        var params: [String : String] = [:]
        
        if let queryPairs = queryString.split(separator: "&").map({ $0.components(separatedBy: "=") }) {
            for pair in queryPairs {
                guard pair.count == 2 else { continue }
                
